import React, { useEffect, useState } from 'react';
import axios from 'axios';
import { useAuth } from '../../context/AuthContext';
import AnimatedNumber from '../../components/AnimatedNumber';

function DetailModal({ title, icon, onClose, children }) {
  return (
    <div className="modal-overlay" onClick={e => e.target === e.currentTarget && onClose()}>
      <div className="modal" style={{ maxWidth: 700 }}>
        <div className="modal-header">
          <span className="modal-title">{icon} {title}</span>
          <button className="modal-close" onClick={onClose}>×</button>
        </div>
        <div style={{ maxHeight: '65vh', overflowY: 'auto' }}>
          {children}
        </div>
      </div>
    </div>
  );
}

export default function StudentDashboard() {
  const { user }  = useAuth();
  const [data,    setData]    = useState(null);
  const [loading, setLoading] = useState(true);
  const [modal,   setModal]   = useState(null);
  const [marks,   setMarks]   = useState([]);
  const [loadingModal, setLoadingModal] = useState(false);

  useEffect(() => {
    axios.get('/api/student/stats')
      .then(res => { setData(res.data); setLoading(false); })
      .catch(() => setLoading(false));
  }, []);

  const openModal = async (type, title, icon) => {
    setModal({ type, title, icon });
    setMarks([]);
    setLoadingModal(true);
    try {
      const params = {};
      if (type === 'mid1') params.midExam = 'Mid-1';
      if (type === 'mid2') params.midExam = 'Mid-2';
      const res = await axios.get('/api/student/marks', { params });
      // Flatten subjects to marks list
      const allMarks = [];
      res.data.subjects.forEach(g => {
        if (type === 'mid1' && g.mid1) allMarks.push({ ...g.mid1, subjectName: g.subject?.name, subjectCode: g.subject?.code });
        else if (type === 'mid2' && g.mid2) allMarks.push({ ...g.mid2, subjectName: g.subject?.name, subjectCode: g.subject?.code });
        else if (type === 'finals' && g.finalVisible) allMarks.push({ subjectName: g.subject?.name, subjectCode: g.subject?.code, finalMarks: g.finalMarks, mid1: g.mid1?.totalMarks, mid2: g.mid2?.totalMarks });
        else if (type === 'subjects') allMarks.push({ subjectName: g.subject?.name, subjectCode: g.subject?.code, sem: g.subject?.semester });
      });
      setMarks(allMarks);
    } catch { setMarks([]); }
    finally { setLoadingModal(false); }
  };

  if (loading) return <div className="loading-screen"><div className="spinner"></div></div>;

  const { stats } = data || { stats: {} };

  const statCards = [
    { key:'semester', value:stats.currentSemester||0, label:'Current Semester', icon:'📅', color:'blue',   title:null },
    { key:'subjects', value:stats.totalSubjects||0,   label:'Total Subjects',   icon:'📚', color:'cyan',   title:'My Subjects' },
    { key:'mid1',     value:stats.mid1Count||0,        label:'Mid-1 Results',    icon:'📝', color:'yellow', title:'My Mid-1 Marks' },
    { key:'mid2',     value:stats.mid2Count||0,        label:'Mid-2 Results',    icon:'📋', color:'green',  title:'My Mid-2 Marks' },
    { key:'avg',      value:stats.avgMid1||0,          label:'Avg Mid-1',        icon:'⭐', color:'purple', title:null },
    { key:'finals',   value:stats.finalReadyCount||0,  label:'Finals Ready',     icon:'🏆', color:'red',    title:'Final Marks Ready' },
  ];

  const patternRows = [
    { component:'Best of Q1/Q2',    max:10, note:'Higher of Q1 or Q2',        bg:'#eff6ff' },
    { component:'Best of Q3/Q4',    max:10, note:'Higher of Q3 or Q4',        bg:'#f0fdf4' },
    { component:'Best of Q5/Q6',    max:10, note:'Higher of Q5 or Q6',        bg:'#fef3c7' },
    { component:'Question Total ÷2',max:15, note:'Sum of above ÷ 2',          bg:'#f8fafc', italic:true },
    { component:'SHA',              max:10, note:'Surprise/Home Assignment',   bg:'#fff' },
    { component:'Assignment',       max:5,  note:'Assignment marks',           bg:'#f8fafc' },
    { component:'Mid Total',        max:30, note:'Per mid exam',               bg:'#e0f2fe', bold:true },
    { component:'Final Marks',      max:30, note:'80% higher + 20% lower mid', bg:'#d1fae5', bold:true },
  ];

  return (
    <div>
      <div className="info-box" style={{ marginBottom:20 }}>
        👋 Welcome, <strong>{user?.name}</strong> &nbsp;|&nbsp;
        Roll: <strong>{user?.rollNumber}</strong> &nbsp;|&nbsp;
        Dept: <strong>{user?.department?.name}</strong> &nbsp;|&nbsp;
        Sem: <strong>{user?.semester}</strong>
      </div>

      <div className="stats-grid">
        {statCards.map(card => (
          <div key={card.key}
            className={`stat-card ${card.color}`}
            onClick={() => card.title && openModal(card.key, card.title, card.icon)}
            style={{ cursor: card.title ? 'pointer' : 'default', userSelect:'none' }}
          >
            <div className="stat-icon">{card.icon}</div>
            <div>
              <div className="stat-value"><AnimatedNumber value={card.value} /></div>
              <div className="stat-label">{card.label}</div>
              {card.title && <div style={{ fontSize:10, color:'var(--primary)', marginTop:2, fontWeight:600 }}>Click to view →</div>}
            </div>
          </div>
        ))}
      </div>

      {/* Marks Pattern Card */}
      <div className="card">
        <div className="card-header"><span className="card-title">📐 Marks Pattern</span></div>
        <div className="card-body" style={{ padding:0 }}>
          {patternRows.map((row,i) => (
            <div key={i} style={{
              display:'flex', alignItems:'center', padding:'11px 16px',
              background:row.bg, borderBottom: i<patternRows.length-1?'1px solid #f1f5f9':'none', gap:12
            }}>
              <div style={{ flex:2, fontSize:13, fontWeight:row.bold?700:400, fontStyle:row.italic?'italic':'normal' }}>{row.component}</div>
              <div style={{ flexShrink:0 }}>
                <span style={{ display:'inline-block', padding:'2px 10px', borderRadius:20, fontSize:13, fontWeight:700, background:row.bold?'#1a56db':'#e2e8f0', color:row.bold?'white':'var(--text)', minWidth:36, textAlign:'center' }}>{row.max}</span>
              </div>
              <div style={{ flex:3, fontSize:12, color:row.bold?'var(--text)':'var(--text-muted)', textAlign:'right' }}>{row.note}</div>
            </div>
          ))}
        </div>
      </div>

      {/* Detail Modal */}
      {modal && (
        <DetailModal title={modal.title} icon={modal.icon} onClose={() => { setModal(null); setMarks([]); }}>
          {loadingModal ? (
            <div className="empty-state" style={{ padding:40 }}><div className="spinner" style={{ margin:'0 auto' }}></div></div>
          ) : marks.length === 0 ? (
            <div className="empty-state"><div className="empty-icon">📭</div><div className="empty-text">No data yet</div></div>
          ) : modal.type === 'finals' ? (
            <table>
              <thead><tr><th>#</th><th>Subject</th><th>Code</th><th>Mid-1</th><th>Mid-2</th><th>Final /30</th></tr></thead>
              <tbody>
                {marks.map((m,i) => (
                  <tr key={i}><td>{i+1}</td>
                    <td className="fw-600">{m.subjectName}</td>
                    <td><span className="badge badge-purple">{m.subjectCode}</span></td>
                    <td>{m.mid1}/30</td><td>{m.mid2}/30</td>
                    <td><strong style={{ color:'var(--success)', fontSize:15 }}>{m.finalMarks}/30</strong></td>
                  </tr>
                ))}
              </tbody>
            </table>
          ) : modal.type === 'subjects' ? (
            <table>
              <thead><tr><th>#</th><th>Subject</th><th>Code</th><th>Semester</th></tr></thead>
              <tbody>
                {marks.map((m,i) => (
                  <tr key={i}><td>{i+1}</td>
                    <td className="fw-600">{m.subjectName}</td>
                    <td><span className="badge badge-purple">{m.subjectCode}</span></td>
                    <td>Sem {m.sem}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          ) : (
            <table>
              <thead><tr><th>#</th><th>Subject</th><th>Q1</th><th>Q2</th><th>Q3</th><th>Q4</th><th>Q5</th><th>Q6</th><th>Asgn</th><th>SHA</th><th>Total</th></tr></thead>
              <tbody>
                {marks.map((m,i) => (
                  <tr key={i}><td>{i+1}</td>
                    <td className="fw-600">{m.subjectName}</td>
                    <td>{m.q1}</td><td>{m.q2}</td><td>{m.q3}</td><td>{m.q4}</td><td>{m.q5}</td><td>{m.q6}</td>
                    <td>{m.assignmentMarks}</td><td>{m.shaMarks}</td>
                    <td><strong style={{ color:'var(--success)' }}>{m.totalMarks}/30</strong></td>
                  </tr>
                ))}
              </tbody>
            </table>
          )}
          <div style={{ padding:'12px 20px', borderTop:'1px solid var(--border)', fontSize:13, color:'var(--text-muted)' }}>
            Total: <strong>{marks.length}</strong> records
          </div>
        </DetailModal>
      )}
    </div>
  );
}
